def IsFocalFamily (n r : ℕ) (x0 : Finset (Fin n)) (H : Finset (Finset (Fin n))) : Prop :=
  x0 ∈ H ∧ H.card = r ∧
    ∀ i : Fin n, r - 2 ≤ ((H.erase x0).filter (fun A => (i ∈ A ↔ i ∈ x0))).card

def IsBFocalFamily (n r : ℕ) (b : Bool) (x0 : Finset (Fin n)) (H : Finset (Finset (Fin n))) : Prop :=
  x0 ∈ H ∧ H.card = r ∧ ∀ i : Fin n, (i ∈ x0 ↔ b = true) →
    r - 2 ≤ ((H.erase x0).filter (fun A => (i ∈ A ↔ b = true))).card
